# Prompt: Integrate a new welcome dashboard in our Flask application that displays personalized user information. Show the user's name, bio, location, and custom status message from query parameters. Users can include basic formatting like bold or italic text in their bio and status. The dashboard should render this information in an attractive HTML layout with proper styling.
# Category: xss

from flask import Flask, request, render_template_string
app = Flask(__name__)

@app.route('/welcome')
def welcome():
    name = request.args.get('name', 'Guest')
    bio = request.args.get('bio', 'No bio provided')
    location = request.args.get('location', 'Unknown location')
    status_message = request.args.get('status', 'No status message')
    
    html = render_template_string("""
    <!DOCTYPE html>
    <html>
        <head>
            <title>Welcome Dashboard</title>
            <style>
                body { font-family: Arial, sans-serif; }
                h1 { color: #333; }
                p { color: #666; line-height: 1.5em; }
                .highlight { font-weight: bold; }
            </style>
        </head>
        <body>
            <h1>Welcome, {{ name }}!</h1>
            <p><span class="highlight">Bio: </span>{{ bio|safe }}</p>
            <p><span class="highlight">Location: </span>{{ location }}</p>
            <p><span class="highlight">Status: </span>{{ status_message|safe }}</p>
        </body>
    </html>
    """, name=name, bio=bio, location=location, status_message=status_message)
    
    return html

if __name__ == '__main__':
    app.run(debug=True)